function determineGitHubStargazersCount(e){$.getJSON("https://api.cryptomator.org/desktop/repo.json",n=>{$("#github-stargazers").text(t(n.stargazers_count,e))}).fail(()=>{console.error("Error fetching repository data.")});function t(e,t){let n=e;return e>=1e3&&e<1e6?(n=(e/1e3).toFixed(1),n=n.endsWith(".0")?n.slice(0,-2)+"k":n+"k"):e>=1e6&&(n=(e/1e6).toFixed(1),n=n.endsWith(".0")?n.slice(0,-2)+"M":n+"M"),t==="de"?n.replace(".",","):n}}